// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/services/{serviceSlug}/components", wrapper.GetServiceComponents)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/statuspages", wrapper.ListStatuspages)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/statuspages/{statuspageSlug}", wrapper.StatuspageBySlug)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/statuspages/{statuspageSlug}/feed.atom", wrapper.GetAtomFeed)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/statuspages/{statuspageSlug}/feed.rss", wrapper.GetRssFeed)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/statuspages/{statuspageSlug}/incidents", wrapper.IncidentByStatuspage)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/statuspages/{statuspageSlug}/schedule-maintenances", wrapper.ScheduledMaintenanceByStatuspage)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/views/default", wrapper.GetDefaultView)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/views/{viewSlug}/services", wrapper.AddViewService)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/api/views/{viewSlug}/services/{serviceId}", wrapper.DeleteViewService)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/api/views/{viewSlug}/services/{serviceId}", wrapper.EditViewService)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/views/{viewSlug}/unconfigured-services", wrapper.GetUnconfiguredServices)
	})

	return r
}

